import { setRenameFolder } from "~/store/features/mediaLibrarySlice";
import { useEffect, useRef, useState } from "@wordpress/element";
import { useCustomAlert } from "~/components/molecules/Alert";
import InlineStack from "~/components/molecules/InlineStack";
import BlockStack from "~/components/molecules/BlockStack";
import Button from "~/components/atoms/Button";
import { useAppDispatch } from "~/store/hooks";
import Input from "~/components/atoms/Input";
import { File } from "~/types/file.types";
import { __ } from "@wordpress/i18n";
/* <fs_premium_only> */
import { useRenameMediaFolderMutation } from "~/store/api/mediaLibraryApi__premium_only";
/* </fs_premium_only> */

const RenameFolder = ({
    folder,
    setCurrentFolder,
    setFolderLoading,
}: {
    folder: File;
    setCurrentFolder?: (folder: File | null) => void;
    setFolderLoading: (loading: boolean) => void;
}) => {
    const [folderName, setFolderName] = useState<string>(folder.name);
    /* <fs_premium_only> */
    const [renameMediaFolder] = useRenameMediaFolderMutation();
    /* </fs_premium_only> */
    const inputRef = useRef<HTMLInputElement | null>(null);

    const dispatch = useAppDispatch();

    const { showAlert } = useCustomAlert();

    useEffect(() => {
        if (inputRef.current) {
            inputRef.current.focus();
            inputRef.current.select();
        }
    }, []);

    const handleRenameFolder = async () => {
        /* <fs_premium_only> */
        if (!folderName) return;

        setFolderLoading(true);

        dispatch(setRenameFolder(""));

        try {
            const response = await renameMediaFolder({
                file_key: folder.file_key,
                name: folderName,
                parentKey: folder.parent_id || "",
            }).unwrap();

            setCurrentFolder?.({
                ...folder,
                name: folderName,
            });

            setFolderLoading(false);

            showAlert({
                toast: true,
                type: "success",
                text:
                    response?.message ||
                    __("Folder renamed successfully", "ninja-drive"),
                timer: 3000,
                timerProgressBar: true,
                showConfirmButton: false,
            });
        } catch (error: any) {
            setFolderLoading(false);

            showAlert({
                toast: true,
                type: "error",
                text:
                    error?.data?.message ||
                    __("Failed to rename folder", "ninja-drive"),
                timer: 3000,
                timerProgressBar: true,
                showConfirmButton: false,
            });
        }
        return;
        /* </fs_premium_only> */
        PNPNDHelper.openUpgradePopUp();
    };

    return (
        <BlockStack gap={8}>
            <Input
                ref={inputRef}
                size="small"
                placeholder={__("Enter new name…", "ninja-drive")}
                value={folderName}
                onChange={(value) => setFolderName(String(value))}
                onKeyDown={(e) => {
                    if (e.key === "Enter") {
                        handleRenameFolder();
                    }
                }}
            />

            <InlineStack gap={10}>
                <Button
                    variant="secondary"
                    size="extrasmall"
                    onClick={() => dispatch(setRenameFolder(""))}
                >
                    {__("Cancel", "ninja-drive")}
                </Button>

                <Button
                    variant="primary"
                    size="extrasmall"
                    onClick={handleRenameFolder}
                >
                    {__("Rename", "ninja-drive")}
                </Button>
            </InlineStack>
        </BlockStack>
    );
};

export default RenameFolder;
