import SkeletonLoader from "~/components/molecules/SkeletonLoader";
import { useAppDispatch, useAppSelector } from "~/store/hooks";
import BlockStack from "~/components/molecules/BlockStack";
import FolderTreeNode from "./FolderTreeNode";
import DnD from "~/components/molecules/DnD";
import { File } from "~/types/file.types";
import CreateFolder from "./CreateFolder";
import AddFolders from "./AddFolders";
import TreeAction from "./TreeAction";
import { MenuKey } from "./Menus";
import {
    addFolders,
    selectMediaLibrary,
    setLoading,
} from "~/store/features/mediaLibrarySlice";
import {
    useEffect,
    useLayoutEffect,
    useRef,
    useState,
} from "@wordpress/element";
/* <fs_premium_only> */
import useMediaLibraryFileActions from "~/hooks/useMediaLibraryFileActions__premium_only";
import { useGetMediaFolderQuery } from "~/store/api/mediaLibraryApi__premium_only";
/* </fs_premium_only> */

const FolderTree = ({ activeMenu }: { activeMenu: MenuKey }) => {
    const { create_folder, active_folder, query_args } =
        useAppSelector(selectMediaLibrary);
    /* <fs_premium_only> */
    const { data, isLoading, isFetching } = useGetMediaFolderQuery(
        {
            folder_key: "",
            order_by: query_args?.order_by,
            order: query_args?.order,
        },
        {
            skip: activeMenu !== "account",
        },
    );

    const { moveFolder, isAddLoading } = useMediaLibraryFileActions();

    const mediaFiles = data?.data?.files || [];

    const loading = isLoading || isAddLoading || isFetching;
    /* </fs_premium_only> */

    const [showFade, setShowFade] = useState(false);
    const ref = useRef<HTMLDivElement | null>(null);

    const dispatch = useAppDispatch();

    /* <fs_premium_only> */
    useEffect(() => {
        dispatch(setLoading(loading));

        if (mediaFiles?.length > 0) {
            dispatch(addFolders(mediaFiles));
        }
    }, [mediaFiles, loading]);
    /* </fs_premium_only> */

    const handleScroll = () => {
        /* <fs_premium_only> */
        if (!ref.current) return;

        const hasScroll = ref.current.scrollHeight > ref.current.clientHeight;

        const reachedBottom =
            ref.current.scrollTop + ref.current.clientHeight >=
            ref.current.scrollHeight - 2;

        setShowFade(hasScroll && !reachedBottom);
        /* </fs_premium_only> */
    };

    /* <fs_premium_only> */
    useLayoutEffect(() => {
        requestAnimationFrame(() => handleScroll());
    }, [data, active_folder]);
    /* </fs_premium_only> */

    return (
        <div style={{ padding: "15px", minWidth: 0 }}>
            <TreeAction
                files={mediaFiles}
                disabled={loading || !mediaFiles || mediaFiles.length === 0}
            />

            {(!mediaFiles || mediaFiles.length === 0) && !loading && (
                <AddFolders />
            )}

            <div
                style={{
                    marginTop: 10,
                }}
                className="pnpnd-media-library-folder-tree"
                onDragOver={(e) => {
                    e.preventDefault();
                    e.stopPropagation();
                }}
                onDrop={(e) => {
                    e.preventDefault();
                    e.stopPropagation();
                }}
            >
                <div
                    ref={ref}
                    onScroll={handleScroll}
                    className="pnpnd-media-library-folder-tree__scroll"
                >
                    {loading ? (
                        Array.from({ length: 20 }).map((_, index) => (
                            <SkeletonLoader
                                key={index}
                                width="100%"
                                height="50px"
                            />
                        ))
                    ) : (
                        <BlockStack>
                            {create_folder && !active_folder && (
                                <CreateFolder />
                            )}

                            <DnD
                                isMove
                                onMove={(from, to) =>
                                    moveFolder(String(to), [String(from)])
                                }
                            >
                                {mediaFiles?.map((folder: File) => (
                                    <DnD.Item
                                        key={folder?.file_key}
                                        id={folder?.file_key}
                                        order={folder?.file_key}
                                    >
                                        <FolderTreeNode
                                            folder={folder}
                                            treePadding={false}
                                        />
                                    </DnD.Item>
                                ))}
                            </DnD>
                        </BlockStack>
                    )}
                </div>

                {showFade && (
                    <div className="pnpnd-media-library-folder-tree__layer" />
                )}
            </div>
        </div>
    );
};

export default FolderTree;
