import { useAppDispatch, useAppSelector } from "~/store/hooks";
import { useCustomAlert } from "~/components/molecules/Alert";
import { useMoveMutation } from "~/store/api/fileApi";
import { __ } from "@wordpress/i18n";
import {
    mediaLibraryApi,
    useAddMediaLibraryFolderMutation,
    useDeleteMediaFolderMutation,
} from "~/store/api/mediaLibraryApi__premium_only";
import {
    selectMediaLibrary,
    setActiveFolder,
    setMoveLoading,
    setSelectedFolders,
} from "~/store/features/mediaLibrarySlice";

const useMediaLibraryFileActions = () => {
    const { active_folder } = useAppSelector(selectMediaLibrary);
    const [addMediaLibraryFolder, { isLoading: isAddLoading }] =
        useAddMediaLibraryFolderMutation();
    const [deleteMediaFolder] = useDeleteMediaFolderMutation();
    const [moveFile] = useMoveMutation();

    const dispatch = useAppDispatch();

    const { showAlert } = useCustomAlert();

    const addFolder = async (keys: string[]) => {
        try {
            const response = await addMediaLibraryFolder({
                folder_keys: keys,
            }).unwrap();

            showAlert({
                toast: true,
                type: "success",
                text:
                    response?.message ||
                    __("Folder added successfully.", "ninja-drive"),
                timer: 3000,
                timerProgressBar: true,
                showConfirmButton: false,
            });
        } catch (error: any) {
            showAlert({
                toast: true,
                type: "error",
                text:
                    error?.data?.message ||
                    __(
                        "An error occurred while adding the folder.",
                        "ninja-drive",
                    ),
                timer: 3000,
                timerProgressBar: true,
                showConfirmButton: false,
            });
        }
    };

    const moveFolder = async (destination: string, folderKeys: string[]) => {
        dispatch(
            setMoveLoading({
                folderKey: destination,
                loading: true,
            }),
        );

        try {
            const response = await moveFile({
                file_keys: folderKeys,
                destination,
                current_folder_key: "",
            }).unwrap();

            dispatch(
                setMoveLoading({
                    folderKey: null,
                    loading: false,
                }),
            );

            dispatch(mediaLibraryApi.util.invalidateTags(["MediaFolders"]));

            showAlert({
                toast: true,
                type: "success",
                text:
                    response?.message ||
                    __("Folder moved successfully.", "ninja-drive"),
                timer: 3000,
                timerProgressBar: true,
                showConfirmButton: false,
            });
        } catch (error: any) {
            dispatch(
                setMoveLoading({
                    folderKey: null,
                    loading: false,
                }),
            );

            showAlert({
                toast: true,
                type: "error",
                text:
                    error?.data?.message ||
                    __(
                        "An error occurred while moving the folder.",
                        "ninja-drive",
                    ),
                timer: 3000,
                timerProgressBar: true,
                showConfirmButton: false,
            });
        }
    };

    const deleteFile = async (folderKeys: string[], parentKey: string) => {
        showAlert({
            type: "error",
            title: "Delete",
            text: "Are you sure you want to delete this folder?",
            showCancelButton: true,
            confirmButtonText: "Delete",
            onConfirm: async () => {
                try {
                    const response = await deleteMediaFolder({
                        folderKeys,
                        parentKey,
                    }).unwrap();

                    folderKeys.forEach((key) => {
                        const isActiveFolder = key === active_folder?.file_key;
                        if (isActiveFolder) {
                            dispatch(setActiveFolder(null));
                        }

                        const el = document.getElementById(key);

                        if (el) {
                            el.style.display = "none";
                        }
                    });

                    dispatch(setSelectedFolders([]));

                    dispatch(
                        mediaLibraryApi.util.invalidateTags(["MediaFolders"]),
                    );

                    showAlert({
                        toast: true,
                        type: "success",
                        text:
                            response?.message ||
                            __("Folder deleted successfully.", "ninja-drive"),
                        timer: 3000,
                        timerProgressBar: true,
                        showConfirmButton: false,
                    });
                } catch (error: any) {
                    showAlert({
                        toast: true,
                        type: "error",
                        text:
                            error?.data?.message ||
                            __(
                                "An error occurred while deleting the folder.",
                                "ninja-drive",
                            ),
                        timer: 3000,
                        timerProgressBar: true,
                        showConfirmButton: false,
                    });
                }
            },
        });
    };

    return { addFolder, moveFolder, deleteFile, isAddLoading };
};

export default useMediaLibraryFileActions;
